#!/usr/bin/env python3
import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = 1  # single test case
    for _ in range(T):
        N = int(next(it))
        min_area = float('inf')
        max_area = 0
        min_idx = max_idx = -1
        for i in range(1, N+1):
            x1 = int(next(it)); y1 = int(next(it))
            x2 = int(next(it)); y2 = int(next(it))
            x3 = int(next(it)); y3 = int(next(it))
            d = abs((x1*(y2-y3) + x2*(y3-y1) + x3*(y1-y2)) / 2)
            if d < min_area:
                min_area = d; min_idx = i
            if d > max_area:
                max_area = d; max_idx = i
        print(min_idx, max_idx)
if __name__ == "__main__":
    solve()

